<?php require "vendor/autoload.php"; $app = require_once "bootstrap/app.php"; $kernel = $app->make(Illuminate\Contracts\Http\Kernel::class); $app->make(Illuminate\Contracts\Console\Kernel::class)->bootstrap(); $user = \App\Models\User::where("role", "customer")->first(); if($user) { \Illuminate\Support\Facades\Auth::login($user); $request = Illuminate\Http\Request::create("/vpn/vmess", "GET"); $response = $kernel->handle($request); echo "Status: " . $response->status() . "\n"; if ($response->status() == 500 && isset($response->exception)) { echo "Exception: " . $response->exception->getMessage() . "\n"; echo "File: " . $response->exception->getFile() . " Line: " . $response->exception->getLine() . "\n"; } } else { echo "No customer"; }
